def main():
    import sys
    sys.setrecursionlimit(1 << 25)
    MOD = 10 ** 9 + 7

    A, C, M = map(int, sys.stdin.readline().split())

    N = A + C + M

    # Precompute factorials and inverse factorials
    maxN = N + 10
    fact = [1] * (maxN)
    invfact = [1] * (maxN)

    for i in range(1, maxN):
        fact[i] = fact[i-1] * i % MOD

    invfact[maxN-1] = pow(fact[maxN-1], MOD-2, MOD)
    for i in range(maxN-2, -1, -1):
        invfact[i] = invfact[i+1] * (i+1) % MOD

    def multinom(a, b, c):
        total = a + b + c
        if min(a, b, c) < 0:
            return 0
        return fact[total] * invfact[a] % MOD * invfact[b] % MOD * invfact[c] % MOD

    # Check if arrangement is possible
    max_count = max(A, C, M)
    if max_count > (N + 1) // 2:
        print(0)
        return

    # DP: dp[a][c][m][last]
    # last: 0=apple, 1=cherry, 2=mango
    from functools import lru_cache

    @lru_cache(maxsize=None)
    def dp(a, c, m, last):
        if a < 0 or c < 0 or m < 0:
            return 0
        if a == 0 and c == 0 and m == 0:
            return 1
        res = 0
        if last != 0 and a > 0:
            res = (res + dp(a-1, c, m, 0)) % MOD
        if last != 1 and c > 0:
            res = (res + dp(a, c-1, m, 1)) % MOD
        if last != 2 and m > 0:
            res = (res + dp(a, c, m-1, 2)) % MOD
        return res

    ans = 0
    if A > 0:
        ans = (ans + dp(A-1, C, M, 0)) % MOD
    if C > 0:
        ans = (ans + dp(A, C-1, M, 1)) % MOD
    if M > 0:
        ans = (ans + dp(A, C, M-1, 2)) % MOD

    print(ans)

