def main():
    import sys

    sys.setrecursionlimit(1 << 25)
    m, k = map(int, sys.stdin.readline().split())

    from functools import lru_cache

    def count_with_k_ones(x, k):
        # Counts numbers in [1, x] with exactly k ones in binary
        if x == 0:
            return 0
        bits = []
        while x:
            bits.append(x & 1)
            x >>= 1
        bits = bits[::-1]
        n = len(bits)

        @lru_cache(maxsize=None)
        def dp(pos, cnt, tight, started):
            if pos == n:
                return int(cnt == k and started)
            res = 0
            up = bits[pos] if tight else 1
            for d in range(up + 1):
                nstarted = started or d
                ncnt = cnt + d if nstarted else cnt
                ntight = tight and (d == up)
                res += dp(pos + 1, ncnt, ntight, nstarted)
            return res

        return dp(0, 0, True, False)

    # Binary search for n
    left, right = 1, 10 ** 18
    answer = -1
    while left <= right:
        mid = (left + right) // 2
        cnt = count_with_k_ones(2 * mid, k) - count_with_k_ones(mid, k)
        if cnt < m:
            left = mid + 1
        else:
            if cnt == m:
                answer = mid
            right = mid - 1

    print(answer)

