def main():
    import sys

    sys.setrecursionlimit(1 << 25)
    n, m = map(int, sys.stdin.readline().split())
    edges = [[] for _ in range(n + 1)]
    for _ in range(m):
        a, b, t = map(int, sys.stdin.readline().split())
        edges[a].append((b, t))
        edges[b].append((a, t))
    dragon_balls = list(map(int, sys.stdin.readline().split()))
    # Remove duplicates, but keep order
    seen = set()
    balls = []
    for c in dragon_balls:
        if c not in seen:
            balls.append(c)
            seen.add(c)
    # Now balls is the list of unique cities with dragon balls (len <= 7)
    # Add city 1 (start) if not already in balls
    if 1 not in balls:
        balls = [1] + balls
    else:
        balls = [1] + [c for c in balls if c != 1]
    k = len(balls)  # k <= 8

    # Map city id to index in balls
    city_to_idx = {city: idx for idx, city in enumerate(balls)}

    # Precompute shortest paths between all pairs of balls cities (including 1)
    # For each city in balls, run Dijkstra
    INF = 1 << 60
    dist = [[INF] * k for _ in range(k)]

    def dijkstra(start_city):
        d = [INF] * (n + 1)
        d[start_city] = 0
        hq = [(0, start_city)]
        while hq:
            cost, u = heapq.heappop(hq)
            if cost > d[u]:
                continue
            for v, w in edges[u]:
                if d[v] > d[u] + w:
                    d[v] = d[u] + w
                    heapq.heappush(hq, (d[v], v))
        return d

    all_dists = []
    for i in range(k):
        d = dijkstra(balls[i])
        all_dists.append(d)
    for i in range(k):
        for j in range(k):
            dist[i][j] = all_dists[i][balls[j]]

    # Check if all balls are reachable from 1
    for i in range(1, k):
        if dist[0][i] == INF:
            print(-1)
            return

    # DP for TSP: dp[mask][u] = min cost to visit mask, ending at u
    dp = [[INF] * k for _ in range(1 << k)]
    dp[1][0] = 0  # Start at city 1 (index 0), only 1 visited

    for mask in range(1 << k):
        for u in range(k):
            if not (mask & (1 << u)):
                continue
            for v in range(k):
                if mask & (1 << v):
                    continue
                if dist[u][v] == INF:
                    continue
                new_mask = mask | (1 << v)
                if dp[new_mask][v] > dp[mask][u] + dist[u][v]:
                    dp[new_mask][v] = dp[mask][u] + dist[u][v]

    # The set of balls to visit is all indices in balls that correspond to the 7 dragon balls
    balls_set = set(dragon_balls)
    mask_needed = 0
    for i, city in enumerate(balls):
        if city in balls_set:
            mask_needed |= (1 << i)
    # We must also include city 1 (index 0) as starting point
    mask_needed |= 1 << 0

    ans = INF
    for u in range(k):
        if (mask_needed & (1 << u)) == 0:
            continue
        if dp[mask_needed][u] < ans:
            ans = dp[mask_needed][u]
    print(ans if ans < INF else -1)

