    n = int(sys.stdin.readline())
    p = list(map(int, sys.stdin.readline().split()))
    tree = [[] for _ in range(n)]
    for i, parent in enumerate(p):
        tree[parent - 1].append(i + 1)

    def dfs(u):
        if not tree[u]:
            return 1
        s = 0
        for v in tree[u]:
            s ^= dfs(v)
        return s + 1

    def dfs2(u):
        if not tree[u]:
            return 1
        res = 0
        for v in tree[u]:
            res += dfs2(v)
        return max(1, res - (res // 2) * 2)

    # The answer is the number of leaves in the tree minus the number of times apples annihilate
    # But actually, the answer is the number of leaves in the tree
    # Because only apples from leaves can reach the root without annihilation
    # But if two leaves have the same path length, they will annihilate at the root
    # So, we need to count the number of unique path lengths from leaves to root

    # Let's compute the depth of each leaf
    depths = []

    def dfs_depth(u, d):
        if not tree[u]:
            depths.append(d)
        for v in tree[u]:
            dfs_depth(v, d + 1)

    dfs_depth(0, 0)
    print(len(set(depths)))

