def is_possible(points, y_sign, r):
    # Try to find a center (cx, cy) with cy = r * y_sign, such that all points are within distance r
    # y_sign = 1 for above y=0, -1 for below y=0
    cy = r * y_sign
    left = -float('inf')
    right = float('inf')
    for x, y in points:
        # Distance from (x, y) to (cx, cy) <= r
        # (cx - x)^2 + (cy - y)^2 <= r^2
        # (cx - x)^2 <= r^2 - (cy - y)^2
        d = r * r - (cy - y) * (cy - y)
        if d < 0:
            return False
        dx = math.sqrt(d)
        left = max(left, x - dx)
        right = min(right, x + dx)
        if left > right:
            return False
    return True

